#!/usr/bin/env python3
"""
Loyola College Students Council Election Server 2026  (v2)
==========================================================
SINGLE SERVER · Port 8080

URLs:
  Student   -> http://<IP>:8080/student
  Officer   -> http://<IP>:8080/officer
  Principal -> http://<IP>:8080/principal
  Dean      -> http://<IP>:8080/dean

Credentials:
  Officer   : pollingofficer / admin123
  Principal : principal / admin
  Dean      : dean / dean@lcm

Workflow:
  1. Principal logs in, clicks "Start Election".
  2. For every student, Polling Officer clicks "Open Voting Session".
     (One session covers BOTH President and Secretary - no separate openings.)
  3. Student votes President -> ballot automatically switches to Secretary
     -> session auto-closes after both votes are cast.
  4. Principal (and only Principal) ends the election.
  5. Results are visible to Principal ONLY AFTER the election is closed.
     Live vote totals are visible (count only, no candidate-wise breakdown).
  6. Dean of Students sees only the overall number of votes polled.
"""

import http.server, json, threading, socket, secrets, time, os
from urllib.parse import urlparse

# ---------- Candidates ------------------------------------------------------
# Candidates are enrolled by the Dean of Students (with photos) and become
# active only after the Principal approves/publishes them.
#
# NOTE: Candidate data (including photos as data: URLs) is stored in-memory.
DEFAULT_PRES_CANDS = []  # 10 items after publish
DEFAULT_SEC_CANDS  = []  # 10 items after publish

LOGO_URI = "data:image/png;base64,"

# ---------- Election state --------------------------------------------------
state = {
    "election_started": False,
    "election_ended":   False,
    # Published candidates (active for election)
    "pres_cands":       list(DEFAULT_PRES_CANDS),
    "sec_cands":        list(DEFAULT_SEC_CANDS),
    "pres_votes":       {},
    "sec_votes":        {},
    "candidates_published": False,

    # Pending candidates (uploaded by Dean, awaiting Principal approval)
    "pending_pres_cands": [],
    "pending_sec_cands":  [],
    "candidates_pending": False,
    "session":          None,
    "student_counter":  0,
    "activity_log":     [],
    "malpractice_alerts": [],
    # When True, student voting is temporarily paused until the Polling Officer
    # acknowledges/silences the alert.
    "ballot_blocked":   False,
    "block_reason":     "",
}
lock = threading.Lock()

def _ts():
    return time.strftime("%H:%M:%S"), time.strftime("%d %b %Y")

def log_event(role, action, detail=""):
    t, d = _ts()
    state["activity_log"].append({"time": t, "date": d, "role": role, "action": action, "detail": detail})
    if len(state["activity_log"]) > 250:
        state["activity_log"] = state["activity_log"][-250:]
    print(f"  >> [{role}] {action} — {detail}")

def log_malpractice(kind, detail):
    t, d = _ts()
    sid = state["student_counter"]
    entry = {
        "time": t,
        "date": d,
        "kind": kind,
        "detail": detail,
        "voter": f"Voter #{sid}" if sid else "Voter",
        "active": True,  # active alerts show as a popup for the Polling Officer
    }
    state["malpractice_alerts"].append(entry)
    if len(state["malpractice_alerts"]) > 80:
        state["malpractice_alerts"] = state["malpractice_alerts"][-80:]
    log_event("STUDENT", "Irregularity", f"{kind}: {detail}")
    print(f"  >> [ALERT] {kind}: {detail}")

def cand_name(post, cid):
    pool = state.get("pres_cands", []) if post == "pres" else state.get("sec_cands", [])
    for c in pool:
        if int(c.get("id", 0)) == int(cid):
            return c.get("name") or "Unknown"
    return "Unknown"

def _rebuild_vote_buckets():
    """Ensure vote dicts match the published candidates."""
    state["pres_votes"] = {int(c["id"]): 0 for c in state.get("pres_cands", [])}
    state["sec_votes"]  = {int(c["id"]): 0 for c in state.get("sec_cands", [])}

def _normalize_candidates(items, min_n=1, max_n=10):
    """
    Convert dean-uploaded candidate payload into a safe list (min..max length).
    Each candidate must include: name, dept, photo (data:image/...).
    """
    if not isinstance(items, list):
        return None, "Invalid candidate format."
    if not (min_n <= len(items) <= max_n):
        return None, f"Please provide between {min_n} and {max_n} candidates."
    out = []
    for i, raw in enumerate(items):
        if not isinstance(raw, dict):
            return None, "Invalid candidate format."
        name = (raw.get("name") or "").strip()
        dept = (raw.get("dept") or "").strip()
        photo = (raw.get("photo") or "").strip()
        if not name or not dept:
            return None, "Candidate name and department are required for all entries."
        if not (photo.startswith("data:image/") and ";base64," in photo):
            return None, "Candidate photo is required for all entries (image upload)."
        # Basic size guard (avoid extremely large payloads in memory)
        if len(photo) > 700_000:
            return None, "One of the photos is too large. Please upload a smaller image."
        out.append({
            "id": i + 1,
            "name": name[:60],
            "dept": dept[:60],
            "photo": photo,
        })
    return out, None

def get_local_ip():
    try:
        s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        s.connect(("8.8.8.8", 80)); ip = s.getsockname()[0]; s.close(); return ip
    except Exception:
        return "127.0.0.1"

def public_status():
    sess = state["session"]
    open_ = sess is not None
    both = open_ and sess.get("pres_done") and sess.get("sec_done")
    pres_total = sum(state.get("pres_votes", {}).values())
    sec_total  = sum(state.get("sec_votes", {}).values())
    return {
        "election_started": state["election_started"],
        "election_ended":   state["election_ended"],
        "session_open":     open_,
        "session_complete": both,
        "ballot_label":     "BALLOT READY" if open_ and not both else ("VOTING COMPLETE" if both else "BALLOT CLOSED"),
        "pres_total":       pres_total,
        "sec_total":        sec_total,
        "total_polled":     min(sum(state["pres_votes"].values()),
                                sum(state["sec_votes"].values())),
        "activity_log":     list(state["activity_log"][-60:]),
        # Only *active* alerts are shown to officials (as a popup).
        "malpractice_alerts": [a for a in state["malpractice_alerts"] if a.get("active")][-12:],
        "ballot_blocked":   bool(state.get("ballot_blocked")),
        "block_reason":     state.get("block_reason", ""),
        "current_voter":    state["student_counter"] if open_ else 0,
        "candidates_published": bool(state.get("candidates_published")),
        "candidates_pending": bool(state.get("candidates_pending")),
    }

